const token = $input.first().json.headers['x-wati-token'];
if (!token || token !== 'CrackTesos2026_WH_Token') {
  return [{json: {ok: 'false', tiene_trivia: 'false'}}];
}
const body = $input.first().json.body;
let phone = (body.phone || '').toString().replace(/[^0-9]/g, '');
if (!phone.startsWith('57') && phone.length === 10) phone = '57' + phone;
if (!phone || phone.length < 10) {
  return [{json: {ok: 'false', tiene_trivia: 'false', mensaje: 'Teléfono inválido'}}];
}
return [{json: {ok: 'true', phone}}];

const phone = $('Validar').first().json.phone;
const rows = $input.all();

if (!rows.length || !rows[0].json.user_id) {
  return [{json: {ok: 'true', tiene_trivia: 'false', mensaje: 'Usuario no registrado en la base.'}}];
}

const d = rows[0].json;

if (!d.trivia_id) {
  return [{json: {ok: 'true', tiene_trivia: 'false', nombre: d.name, mensaje: '¡No hay trivia activa en este momento! Cuando enviemos la próxima, te llegará la invitación. 🏆'}}];
}

if (parseInt(d.ya_respondio) > 0) {
  return [{json: {
    ok: 'true', tiene_trivia: 'false',
    nombre: d.name,
    numero_trivia: String(d.trivia_number),
    mensaje: `Ya respondiste la Trivia #${d.trivia_number}. ¡Espera la próxima! 💪`
  }}];
}

const secsRemaining = Math.max(0, Math.floor(parseFloat(d.seconds_remaining || 0)));
const hoursRemaining = Math.floor(secsRemaining / 3600);
const minsRemaining = Math.floor((secsRemaining % 3600) / 60);
const timeLabel = hoursRemaining > 0 ? `${hoursRemaining}h ${minsRemaining}m` : `${minsRemaining} minutos`;

return [{json: {
  ok: 'true',
  tiene_trivia: 'true',
  nombre: d.name,
  trivia_id: d.trivia_id,
  numero_trivia: String(d.trivia_number),
  question: d.question,
  option_a: d.option_a,
  option_b: d.option_b,
  option_c: d.option_c,
  tiene_multiplicador: d.has_multiplier ? 'true' : 'false',
  horas_restantes: timeLabel,
  total_goles: String(d.total_goals || 0)
}}];
